package com.aadil.jobtracker.security;import com.aadil.jobtracker.UserService.UserServiceDetailsImp;import jakarta.servlet.FilterChain;import jakarta.servlet.ServletException;import jakarta.servlet.http.HttpServletRequest;import jakarta.servlet.http.HttpServletResponse;import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;import org.springframework.security.core.context.SecurityContextHolder;import org.springframework.security.core.userdetails.UserDetails;import org.springframework.stereotype.Component;import org.springframework.web.filter.OncePerRequestFilter;import java.io.IOException;@Componentpublic class JwtFilter extends OncePerRequestFilter {    private final JwtUtility jwtUtility;    private final UserServiceDetailsImp userServiceDetails;    public JwtFilter(JwtUtility jwtUtility, UserServiceDetailsImp userServiceDetails) {        this.jwtUtility = jwtUtility;        this.userServiceDetails = userServiceDetails;    }    @Override    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain) throws ServletException, IOException {        String header=request.getHeader("Authorization");        if (header==null||!header.startsWith("Bearer")){            filterChain.doFilter(request,response);            return;        }        String token=header.substring(7);        String username= jwtUtility.extractUsername(token);        if (username!=null&& SecurityContextHolder.getContext().getAuthentication()==null){            UserDetails userDetails=userServiceDetails.loadUserByUsername(username);            if (jwtUtility.validateToken(token,userDetails.getUsername())){                UsernamePasswordAuthenticationToken auth=new UsernamePasswordAuthenticationToken(userDetails,null,userDetails.getAuthorities());                SecurityContextHolder.getContext().setAuthentication(auth);            }        }        filterChain.doFilter(request,response);    }}